class Solution:
    def convert(self, s, numRows):
        if numRows == 1:
            return s
        cycle = 2 * numRows - 2
        rows = []
        for r in range(numRows):
            row = []
            for i, c in enumerate(s):
                pos = i % cycle
                if pos == r or pos == cycle - r:
                    row.append(c)
            rows.append(''.join(row))
        return ''.join(rows)

