var convert = function(s, numRows) {
    if (numRows === 1 || numRows >= s.length) return s;
    const rows = Array.from({length: numRows}, () => []);
    let r = 0, step = 1;
    for (const c of s) {
        rows[r].push(c);
        if (r === 0) step = 1;
        else if (r === numRows - 1) step = -1;
        r += step;
    }
    return rows.map(row => row.join('')).join('');
};
